import '../Styles/abogada.css';

function abogadas({ nombre, imagen, especialidades }){
  return (
    <div className="abogada">
      <div className="abogada-img-container">
        <img src={imagen} alt={nombre} className="abogada-img" />
      </div>

      <div className="abogada-info">
        <h3 className="abogada-nombre">{nombre}</h3>

        <ul className="abogada-lista">
          {especialidades.map((esp, i) => (
            <li key={i}>{esp}</li>
          ))}
        </ul>
      </div>
    </div>
  );
}

export default abogadas;
